etb18 <- haven::read_dta("./data/BIBBBAuA_2018_suf1.0.dta",col_select = c("F518_SUF","az","S1","m1202")) %>% 
  mutate(across(matches("F518"),~ifelse(.x<0 | .x > 99998, NA, .x)),
         gender = factor(S1,levels = 1:2, labels = c("m","w")),
         educ = as_factor(m1202))

m1 <- lm(F518_SUF ~ az + I(az^2) + gender + educ, data = etb18)

mx <- modelsummary::modelsummary(m1,output = "flextable")
```
